begin;

insert into public.hechos (id, numero, ordinal, capitulo_id, resumen, texto_completo, texto_completo_html, titulo_corto, nota_abogado)
select id, numero, ordinal, capitulo_id, resumen, texto_completo, texto_completo_html, titulo_corto, nota_abogado
from jsonb_to_recordset($hechos$[{"id":"hecho-53","numero":53,"ordinal":"QUINCUAGESIMOTERCERO","capitulo_id":"cap-15","resumen":"Entre febrero de 2024 y septiembre de 2025, se documentaron **376 comprobantes de pago** de estudiantes del programa ParetoMed, correspondientes a transacciones procesadas a traves de las plataformas Bold (190 pagos, $331.646.650), Bancolombia (106 p...","texto_completo":"**HECHO QUINCUAGESIMOTERCERO.** Entre febrero de 2024 y septiembre de 2025, se documentaron **376 comprobantes de pago** de estudiantes del programa ParetoMed, correspondientes a transacciones procesadas a traves de las plataformas Bold (190 pagos, $331.646.650), Bancolombia (106 pagos, $134.101.446), PSE-Wompi (27 pagos, $44.909.150), Boton Bancolombia (8 pagos, $16.535.000), BBVA (8 pagos, $11.205.000), Scotiabank (3 pagos, $6.732.000) y otras plataformas no identificadas (30 pagos, $34.088.250). El **total de ingresos brutos documentados** asciende a **$579.217.496 COP**, con 372 de 376 pagos con monto valido (99%) y 371 de 376 con confianza alta o media en la extraccion de datos (98.7%). El promedio por pago fue de $1.557.036 COP. Estos comprobantes obran como prueba [P-42] en formato Excel y CSV con detalle de fecha, monto, plataforma y referencia de cada transaccion. **[P-42]**\n\n### B. Analisis de consistencia: comprobantes vs. transferencias a Pedro","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMOTERCERO.</strong> Entre febrero de 2024 y septiembre de 2025, se documentaron <strong>376 comprobantes de pago</strong> de estudiantes del programa ParetoMed, correspondientes a transacciones procesadas a traves de las plataformas Bold (190 pagos, $331.646.650), Bancolombia (106 pagos, $134.101.446), PSE-Wompi (27 pagos, $44.909.150), Boton Bancolombia (8 pagos, $16.535.000), BBVA (8 pagos, $11.205.000), Scotiabank (3 pagos, $6.732.000) y otras plataformas no identificadas (30 pagos, $34.088.250). El <strong>total de ingresos brutos documentados</strong> asciende a <strong>$579.217.496 COP</strong>, con 372 de 376 pagos con monto valido (99%) y 371 de 376 con confianza alta o media en la extraccion de datos (98.7%). El promedio por pago fue de $1.557.036 COP. Estos comprobantes obran como prueba [P-42] en formato Excel y CSV con detalle de fecha, monto, plataforma y referencia de cada transaccion. <strong>[P-42]</strong></p>\n<h3>B. Analisis de consistencia: comprobantes vs. transferencias a Pedro</h3>\n","titulo_corto":"376 comprobantes — $579M en ingresos documentados","nota_abogado":null},{"id":"hecho-54","numero":54,"ordinal":"QUINCUAGESIMOCUARTO","capitulo_id":"cap-15","resumen":"El cruce de los comprobantes de estudiantes con las transferencias recibidas por Pedro arroja una consistencia reveladora: tomando solo el **subtotal de la cuenta personal** documentado por SMS Bancolombia (**$99.319.834 COP**), ese valor equivale al...","texto_completo":"**HECHO QUINCUAGESIMOCUARTO.** El cruce de los comprobantes de estudiantes con las transferencias recibidas por Pedro arroja una consistencia reveladora: tomando solo el **subtotal de la cuenta personal** documentado por SMS Bancolombia (**$99.319.834 COP**), ese valor equivale al **19.48%** de los **$509.900.000** documentados en comprobantes para el periodo comparable (abril 2024 - agosto 2025), porcentaje virtualmente identico al 20% pactado. Al incorporar los pagos canalizados a traves de DOCTOR FLIGHT S.A.S. (**$23.025.231 COP**), el **total acreditado** asciende a **$122.345.065 COP**, equivalente al **24.0%** de esa misma muestra. Esa diferencia confirma que los 376 comprobantes son una **muestra parcial** de los ingresos totales del negocio y no el universo completo de recaudos. **[P-42, P-36, P-37, P-12, P-02]**\n\n### C. Proyeccion de ingresos reales del negocio","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMOCUARTO.</strong> El cruce de los comprobantes de estudiantes con las transferencias recibidas por Pedro arroja una consistencia reveladora: tomando solo el <strong>subtotal de la cuenta personal</strong> documentado por SMS Bancolombia (<strong>$99.319.834 COP</strong>), ese valor equivale al <strong>19.48%</strong> de los <strong>$509.900.000</strong> documentados en comprobantes para el periodo comparable (abril 2024 - agosto 2025), porcentaje virtualmente identico al 20% pactado. Al incorporar los pagos canalizados a traves de DOCTOR FLIGHT S.A.S. (<strong>$23.025.231 COP</strong>), el <strong>total acreditado</strong> asciende a <strong>$122.345.065 COP</strong>, equivalente al <strong>24.0%</strong> de esa misma muestra. Esa diferencia confirma que los 376 comprobantes son una <strong>muestra parcial</strong> de los ingresos totales del negocio y no el universo completo de recaudos. <strong>[P-42, P-36, P-37, P-12, P-02]</strong></p>\n<h3>C. Proyeccion de ingresos reales del negocio</h3>\n","titulo_corto":"Cruce comprobantes vs pagos — 24.0% sobre muestra","nota_abogado":null},{"id":"hecho-55","numero":55,"ordinal":"QUINCUAGESIMOQUINTO","capitulo_id":"cap-15","resumen":"Si Pedro recibio **$122.345.065 COP** como el 20% de las utilidades netas, y el margen de ganancia documentado por Oscar oscilaba entre 56% y 81% (con un promedio conservador de 65%), los ingresos brutos reales del negocio se estiman en aproximadamen...","texto_completo":"**HECHO QUINCUAGESIMOQUINTO.** Si Pedro recibio **$122.345.065 COP** como el 20% de las utilidades netas, y el margen de ganancia documentado por Oscar oscilaba entre 56% y 81% (con un promedio conservador de 65%), los ingresos brutos reales del negocio se estiman en aproximadamente **$941.115.885 COP** ($122.345.065 / 0.20 / 0.65). Los comprobantes documentados (**$579.217.496**) capturan aproximadamente el **62%** de esos ingresos estimados. La diferencia de alrededor de **$362.000.000** corresponde a pagos de estudiantes cuyos comprobantes no fueron enviados por Adriana, recuperacion de cartera, cuotas en mora pagadas posteriormente y ventas no reportadas por la asesora. Esta proyeccion es consistente con los KPIs de Oscar para 2025, que reportaban ventas totales de entre $46M y $97M mensuales. **[P-42, P-02, P-13, P-12]**\n\n### D. Negativa de Oscar a rendir cuentas y exhibir su contabilidad personal","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMOQUINTO.</strong> Si Pedro recibio <strong>$122.345.065 COP</strong> como el 20% de las utilidades netas, y el margen de ganancia documentado por Oscar oscilaba entre 56% y 81% (con un promedio conservador de 65%), los ingresos brutos reales del negocio se estiman en aproximadamente <strong>$941.115.885 COP</strong> ($122.345.065 / 0.20 / 0.65). Los comprobantes documentados (<strong>$579.217.496</strong>) capturan aproximadamente el <strong>62%</strong> de esos ingresos estimados. La diferencia de alrededor de <strong>$362.000.000</strong> corresponde a pagos de estudiantes cuyos comprobantes no fueron enviados por Adriana, recuperacion de cartera, cuotas en mora pagadas posteriormente y ventas no reportadas por la asesora. Esta proyeccion es consistente con los KPIs de Oscar para 2025, que reportaban ventas totales de entre $46M y $97M mensuales. <strong>[P-42, P-02, P-13, P-12]</strong></p>\n<h3>D. Negativa de Oscar a rendir cuentas y exhibir su contabilidad personal</h3>\n","titulo_corto":"Proyección de ingresos reales — $941M estimados","nota_abogado":null},{"id":"hecho-56","numero":56,"ordinal":"QUINCUAGESIMOSEXTO","capitulo_id":"cap-15","resumen":"El 28 de febrero de 2025, Oscar revelo en el chat de WhatsApp la existencia de una **hoja de calculo personal** con la contabilidad detallada del negocio, distinta de los consolidados que compartia con Pedro: *\"yo me guio de la hoja de calculo person...","texto_completo":"**HECHO QUINCUAGESIMOSEXTO.** El 28 de febrero de 2025, Oscar revelo en el chat de WhatsApp la existencia de una **hoja de calculo personal** con la contabilidad detallada del negocio, distinta de los consolidados que compartia con Pedro: *\"yo me guio de la hoja de calculo personal mia\"*. Pedro solicito acceso a esta hoja de calculo y Oscar se nego. El 5 de agosto de 2025, cuando Pedro pidio el ultimo consolidado, Oscar respondio con hostilidad: *\"Joda, no tengo porque hacerlo y me ofende que me lo pidas\"*, lo que constituye una negativa expresa a rendir cuentas a su socio. Esta negativa es contraria al deber de informacion entre socios (articulo 504 del Codigo de Comercio) y genera un indicio grave de que la contabilidad interna de Oscar podria revelar ingresos superiores a los reportados en los consolidados compartidos con Pedro. La existencia de esta hoja de calculo debe ser objeto de exhibicion de documentos (articulo 265 CGP) en el proceso. **[P-47, P-48, P-02]**\n\n### E. Diferencia entre facturacion de servicios (Avanz) y participacion societaria (ParetoMed)","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMOSEXTO.</strong> El 28 de febrero de 2025, Oscar revelo en el chat de WhatsApp la existencia de una <strong>hoja de calculo personal</strong> con la contabilidad detallada del negocio, distinta de los consolidados que compartia con Pedro: <em>&quot;yo me guio de la hoja de calculo personal mia&quot;</em>. Pedro solicito acceso a esta hoja de calculo y Oscar se nego. El 5 de agosto de 2025, cuando Pedro pidio el ultimo consolidado, Oscar respondio con hostilidad: <em>&quot;Joda, no tengo porque hacerlo y me ofende que me lo pidas&quot;</em>, lo que constituye una negativa expresa a rendir cuentas a su socio. Esta negativa es contraria al deber de informacion entre socios (articulo 504 del Codigo de Comercio) y genera un indicio grave de que la contabilidad interna de Oscar podria revelar ingresos superiores a los reportados en los consolidados compartidos con Pedro. La existencia de esta hoja de calculo debe ser objeto de exhibicion de documentos (articulo 265 CGP) en el proceso. <strong>[P-47, P-48, P-02]</strong></p>\n<h3>E. Diferencia entre facturacion de servicios (Avanz) y participacion societaria (ParetoMed)</h3>\n","titulo_corto":"Oscar oculta contabilidad y se niega a rendir cuentas","nota_abogado":null},{"id":"hecho-57","numero":57,"ordinal":"QUINCUAGESIMOSEPTIMO","capitulo_id":"cap-15","resumen":"La comparacion entre la facturacion de Pedro a AVANZ FINANZAS & SEGUROS LTDA (NIT 901286973-7) y la facturacion a Oscar/ParetoMed demuestra que Pedro distinguia perfectamente entre una relacion de prestacion de servicios y una relacion societaria. Co...","texto_completo":"**HECHO QUINCUAGESIMOSEPTIMO.** La comparacion entre la facturacion de Pedro a AVANZ FINANZAS & SEGUROS LTDA (NIT 901286973-7) y la facturacion a Oscar/ParetoMed demuestra que Pedro distinguia perfectamente entre una relacion de prestacion de servicios y una relacion societaria. Con Avanz, Pedro facturaba con concepto especifico de *\"Creacion de contenido / guiones comerciales, produccion y edicion de videos publicitarios para redes sociales\"*, a tarifa fija por entregable ($1.680.672 + adicionales), con cesion de derechos de autor implicita. Con Oscar/ParetoMed, la facturacion era radicalmente distinta: concepto generico de *\"COMISION\"* o *\"Gestion de redes y campanas\"*, monto variable calculado sobre el 20% de utilidades netas (sin entregables especificos facturados), y el **75% de los pagos ($74.900.000) se hicieron SIN factura ni cuenta de cobro**. Si la relacion con ParetoMed fuera una simple prestacion de servicios de contenido, Pedro habria facturado exactamente igual que con Avanz — tarifa fija, concepto de creacion de contenido, con cesion de derechos. No lo hizo porque NO era eso: era participacion de socio industrial en utilidades. **[P-42, P-46, P-12]**\n\n### F. Utilidades post-ruptura documentadas con KPIs del demandado","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMOSEPTIMO.</strong> La comparacion entre la facturacion de Pedro a AVANZ FINANZAS &amp; SEGUROS LTDA (NIT 901286973-7) y la facturacion a Oscar/ParetoMed demuestra que Pedro distinguia perfectamente entre una relacion de prestacion de servicios y una relacion societaria. Con Avanz, Pedro facturaba con concepto especifico de <em>&quot;Creacion de contenido / guiones comerciales, produccion y edicion de videos publicitarios para redes sociales&quot;</em>, a tarifa fija por entregable ($1.680.672 + adicionales), con cesion de derechos de autor implicita. Con Oscar/ParetoMed, la facturacion era radicalmente distinta: concepto generico de <em>&quot;COMISION&quot;</em> o <em>&quot;Gestion de redes y campanas&quot;</em>, monto variable calculado sobre el 20% de utilidades netas (sin entregables especificos facturados), y el <strong>75% de los pagos ($74.900.000) se hicieron SIN factura ni cuenta de cobro</strong>. Si la relacion con ParetoMed fuera una simple prestacion de servicios de contenido, Pedro habria facturado exactamente igual que con Avanz — tarifa fija, concepto de creacion de contenido, con cesion de derechos. No lo hizo porque NO era eso: era participacion de socio industrial en utilidades. <strong>[P-42, P-46, P-12]</strong></p>\n<h3>F. Utilidades post-ruptura documentadas con KPIs del demandado</h3>\n","titulo_corto":"Facturación Avanz vs ParetoMed — dos modelos distintos","nota_abogado":null},{"id":"hecho-58","numero":58,"ordinal":"QUINCUAGESIMOCTAVO","capitulo_id":"cap-15","resumen":"Los KPIs de ventas de ParetoMed para 2025, contenidos en la hoja de calculo \"Copia de KPIS 2025.xlsx\" (archivo del demandado en poder del demandante), documentan que Oscar continuo explotando el negocio despues de la ruptura con los siguientes ingres...","texto_completo":"**HECHO QUINCUAGESIMOCTAVO.** Los KPIs de ventas de ParetoMed para 2025, contenidos en la hoja de calculo \"Copia de KPIS 2025.xlsx\" (archivo del demandado en poder del demandante), documentan que Oscar continuo explotando el negocio despues de la ruptura con los siguientes ingresos: agosto 2025: $52.790.000; septiembre 2025: $52.640.800; octubre 2025: $64.057.500. Total periodo post-ruptura: **$169.488.300 COP**. Aplicando el margen de ganancia del 65% documentado en los consolidados de Oscar y la participacion del 20% pactada, las utilidades adeudadas a Pedro por este periodo ascienden a **$22.033.479 COP**. El negocio continuo operando hasta al menos diciembre 2025 (noviembre: $84.102.500; diciembre: $46.050.000), periodo cuyas utilidades tambien podrian ser reclamables. La ultima transferencia de Oscar a Pedro ($7.450.000 del 05/08/2025) cubria el mes de julio 2025, por lo que agosto en adelante se adeuda integramente. **[P-43, P-02]**\n\n---","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMOCTAVO.</strong> Los KPIs de ventas de ParetoMed para 2025, contenidos en la hoja de calculo &quot;Copia de KPIS 2025.xlsx&quot; (archivo del demandado en poder del demandante), documentan que Oscar continuo explotando el negocio despues de la ruptura con los siguientes ingresos: agosto 2025: $52.790.000; septiembre 2025: $52.640.800; octubre 2025: $64.057.500. Total periodo post-ruptura: <strong>$169.488.300 COP</strong>. Aplicando el margen de ganancia del 65% documentado en los consolidados de Oscar y la participacion del 20% pactada, las utilidades adeudadas a Pedro por este periodo ascienden a <strong>$22.033.479 COP</strong>. El negocio continuo operando hasta al menos diciembre 2025 (noviembre: $84.102.500; diciembre: $46.050.000), periodo cuyas utilidades tambien podrian ser reclamables. La ultima transferencia de Oscar a Pedro ($7.450.000 del 05/08/2025) cubria el mes de julio 2025, por lo que agosto en adelante se adeuda integramente. <strong>[P-43, P-02]</strong></p>\n<hr>\n","titulo_corto":"KPIs post-ruptura — $169M en ventas sin pagar a Pedro","nota_abogado":null}]$hechos$::jsonb)
  as x(id text, numero integer, ordinal text, capitulo_id text, resumen text, texto_completo text, texto_completo_html text, titulo_corto text, nota_abogado text)
on conflict (id) do update set
  numero = excluded.numero,
  ordinal = excluded.ordinal,
  capitulo_id = excluded.capitulo_id,
  resumen = excluded.resumen,
  texto_completo = excluded.texto_completo,
  texto_completo_html = excluded.texto_completo_html,
  titulo_corto = excluded.titulo_corto,
  nota_abogado = excluded.nota_abogado;

insert into public.pruebas (id, descripcion, tipo, categoria)
select id, descripcion, tipo, categoria
from jsonb_to_recordset($pruebas$[{"id":"P-36","descripcion":"Transferencias bancarias Bancolombia cuenta 4483 de Pedro Vergara (14 transferencias a cuenta personal, $99.319.834 subtotal)","tipo":"Prueba financiera","categoria":null}]$pruebas$::jsonb)
  as x(id text, descripcion text, tipo text, categoria text)
on conflict (id) do update set
  descripcion = excluded.descripcion,
  tipo = excluded.tipo,
  categoria = excluded.categoria;

delete from public.hecho_pruebas where hecho_id in (select jsonb_array_elements_text($ids$["hecho-53","hecho-54","hecho-55","hecho-56","hecho-57","hecho-58"]$ids$::jsonb));
insert into public.hecho_pruebas (hecho_id, prueba_id)
select hecho_id, prueba_id
from jsonb_to_recordset($rel$[{"hecho_id":"hecho-53","prueba_id":"P-42"},{"hecho_id":"hecho-54","prueba_id":"P-42"},{"hecho_id":"hecho-54","prueba_id":"P-36"},{"hecho_id":"hecho-54","prueba_id":"P-37"},{"hecho_id":"hecho-54","prueba_id":"P-12"},{"hecho_id":"hecho-54","prueba_id":"P-02"},{"hecho_id":"hecho-55","prueba_id":"P-42"},{"hecho_id":"hecho-55","prueba_id":"P-02"},{"hecho_id":"hecho-55","prueba_id":"P-13"},{"hecho_id":"hecho-55","prueba_id":"P-12"},{"hecho_id":"hecho-56","prueba_id":"P-47"},{"hecho_id":"hecho-56","prueba_id":"P-48"},{"hecho_id":"hecho-56","prueba_id":"P-02"},{"hecho_id":"hecho-57","prueba_id":"P-42"},{"hecho_id":"hecho-57","prueba_id":"P-46"},{"hecho_id":"hecho-57","prueba_id":"P-12"},{"hecho_id":"hecho-58","prueba_id":"P-43"},{"hecho_id":"hecho-58","prueba_id":"P-02"}]$rel$::jsonb)
  as x(hecho_id text, prueba_id text)
on conflict do nothing;

delete from public.fragmentos_clave where hecho_id in (select jsonb_array_elements_text($ids$["hecho-53","hecho-54","hecho-55","hecho-56","hecho-57","hecho-58"]$ids$::jsonb));
insert into public.fragmentos_clave (hecho_id, cita, fuente, linea, fecha, autor, relevancia)
select hecho_id, cita, fuente, linea, fecha, autor, relevancia
from jsonb_to_recordset($frag$[{"hecho_id":"hecho-53","cita":"376 comprobantes de pago de estudiantes del programa ParetoMed, correspondientes a transacciones procesadas a traves de las plataformas Bold (190 pagos, $331.646.650), Bancolombia (106 pagos, $134.101.446)","fuente":"doc-comprobantes-excel","linea":null,"fecha":"feb 2024 - sep 2025","autor":"Adriana / ParetoMed","relevancia":"376 comprobantes multi-plataforma documentan ingresos mínimos de $579M — P-42. Base para el peritaje contable solicitado al despacho"},{"hecho_id":"hecho-53","cita":"El total de ingresos brutos documentados asciende a $579.217.496 COP","fuente":"doc-comprobantes-excel","linea":null,"fecha":"2025","autor":"Pedro Vergara","relevancia":"Ingresos brutos mínimos documentados con 99% de confianza — P-42. Cualquier peritaje de menores ingresos quedaría desvirtuado por este comprobante directo"},{"hecho_id":"hecho-54","cita":"El cruce entre los pagos acreditados a Pedro y los comprobantes del periodo comparable arroja una proporcion practicamente identica al 20% pactado","fuente":"doc-comprobantes-excel","linea":400,"fecha":"feb 2024 - sep 2025","autor":"ParetoMed","relevancia":"La hoja resumen del Excel consolida $509.884.596 para el periodo comparable — P-42. Ese total, cruzado con los pagos acreditados a Pedro, respalda la inferencia contable del 20%"},{"hecho_id":"hecho-54","cita":"Oscar seguia liquidando a Pedro como un porcentaje fijo de la rentabilidad mensual, no como honorarios preestablecidos","fuente":"chat-oscar-pedro","linea":19234,"fecha":"03/02/2025","autor":"Oscar Maldonado","relevancia":"La propia liquidación de Oscar usa el 20% como regla de pago — P-02. Esa mecánica es la que luego se refleja al comparar pagos totales contra ingresos documentados"},{"hecho_id":"hecho-55","cita":"Si Pedro recibia el 20% de las utilidades netas, los ingresos brutos reales del negocio debian superar ampliamente la muestra parcial de comprobantes remitidos","fuente":"chat-oscar-pedro","linea":19234,"fecha":"03/02/2025","autor":"Oscar Maldonado","relevancia":"Oscar documentó simultáneamente rentabilidad neta y participación del 20% — P-02. Esa relación permite proyectar ingresos brutos a partir de los pagos totales acreditados a Pedro"},{"hecho_id":"hecho-55","cita":"Los KPIs de 2025 son compatibles con una escala de ingresos muy superior a la muestra parcial de comprobantes","fuente":"doc-kpis-2025","linea":null,"fecha":"2025","autor":"Oscar Maldonado","relevancia":"La hoja mensual de KPIs muestra meses de $57M, $63M y más — P-43. Sirve como ancla objetiva para la proyección conservadora de ingresos brutos"},{"hecho_id":"hecho-55","cita":"Esta proyeccion es consistente con los KPIs de Oscar para 2025, que reportaban ventas totales de entre $46M y $97M mensuales","fuente":"doc-kpis-2025","linea":null,"fecha":"2025","autor":"Oscar Maldonado","relevancia":"Los KPIs propios de Oscar validan la proyección de Pedro — P-43. El demandado no puede contradecir sus propios datos"},{"hecho_id":"hecho-56","cita":"yo me guio de la hoja de calculo personal mia","fuente":"chat-oscar-pedro","linea":20658,"fecha":"28/02/2025","autor":"Oscar Maldonado","relevancia":"Oscar revela contabilidad paralela personal oculta — P-47. Esta hoja de cálculo debe ser objeto de EXHIBICIÓN DE DOCUMENTOS (art. 265 CGP) en el proceso"},{"hecho_id":"hecho-56","cita":"Joda, no tengo porque hacerlo y me ofende que me lo pidas","fuente":"chat-oscar-pedro","linea":31583,"fecha":"05/08/2025","autor":"Oscar Maldonado","relevancia":"Oscar se niega expresamente a rendir cuentas — P-48. Esta negativa viola el deber de información entre socios (art. 504 C. de Co.) y genera indicio grave de contabilidad oculta"},{"hecho_id":"hecho-57","cita":"con Avanz, Pedro facturaba con concepto especifico de 'Creacion de contenido / guiones comerciales, produccion y edicion de videos publicitarios para redes sociales', a tarifa fija por entregable ($1.680.672 + adicionales)","fuente":"doc-facturas-avanz","linea":null,"fecha":"2024-2025","autor":"Doctor Flight S.A.S.","relevancia":"Facturación a Avanz: concepto específico, tarifa fija, cesión de derechos — P-46 (FE1-FE15). Modelo completamente diferente al de ParetoMed"},{"hecho_id":"hecho-57","cita":"La regularizacion tributaria se pidio tardíamente, meses despues de haber venido pagando, lo que es incompatible con una relación de servicios mensuales regularmente facturada","fuente":"chat-oscar-pedro","linea":17849,"fecha":"17/12/2024","autor":"Oscar Maldonado","relevancia":"Oscar pidió soporte fiscal acumulado en diciembre de 2024 — P-02. Esa regularización tardía solo tiene sentido si previamente no existía facturación contemporánea por cada pago"},{"hecho_id":"hecho-58","cita":"agosto 2025: $52.790.000; septiembre 2025: $52.640.800; octubre 2025: $64.057.500. Total periodo post-ruptura: $169.488.300 COP","fuente":"doc-kpis-2025","linea":null,"fecha":"2025","autor":"Oscar Maldonado","relevancia":"KPIs DEL PROPIO DEMANDADO documentan $169M de ingresos post-ruptura — P-43. Aplicando 65% de margen y 20% de participación = $22M adeudados a Pedro solo en Q3 2025"},{"hecho_id":"hecho-58","cita":"noviembre: $84.102.500; diciembre: $46.050.000","fuente":"doc-kpis-2025","linea":null,"fecha":"2025","autor":"Oscar Maldonado","relevancia":"Ingresos adicionales Q4 2025 — P-43. Las utilidades de noviembre-diciembre también podrían ser reclamables si el juez fija la ruptura en fecha posterior"}]$frag$::jsonb)
